import React, { useRef } from 'react';
import { motion, useInView } from 'framer-motion';
import { HiMail, HiPhone } from 'react-icons/hi';
import { FiGithub, FiLinkedin, FiArrowUpRight } from 'react-icons/fi';

const CARDS = [
  {
    icon: HiMail,
    label: 'Email',
    value: 'hanaharis95@gmail.com',
    href: 'mailto:hanaharis95@gmail.com',
    gradient: 'from-[#6c63ff] to-[#a78bfa]',
    hover: 'hover:border-[#6c63ff]/30',
  },
  {
    icon: HiPhone,
    label: 'Phone',
    value: '+91 85904 42650',
    href: 'tel:+918590442650',
    gradient: 'from-[#38bdf8] to-[#0ea5e9]',
    hover: 'hover:border-[#38bdf8]/30',
  },
  {
    icon: FiGithub,
    label: 'GitHub',
    value: 'github.com/Hanah7511',
    href: 'https://github.com/Hanah7511',
    gradient: 'from-slate-400 to-slate-500',
    hover: 'hover:border-slate-500/30',
    external: true,
  },
  {
    icon: FiLinkedin,
    label: 'LinkedIn',
    value: 'hana-al-haris',
    href: 'https://linkedin.com/in/hana-al-haris-3b7528255',
    gradient: 'from-blue-400 to-blue-600',
    hover: 'hover:border-blue-500/30',
    external: true,
  },
];

function ContactCard({ card, index }) {
  const ref = useRef(null);
  const isInView = useInView(ref, { once: true, margin: '-60px' });
  const Icon = card.icon;

  return (
    <motion.a
      ref={ref}
      href={card.href}
      target={card.external ? '_blank' : undefined}
      rel={card.external ? 'noopener noreferrer' : undefined}
      initial={{ opacity: 0, y: 25 }}
      animate={isInView ? { opacity: 1, y: 0 } : {}}
      transition={{ duration: 0.55, delay: index * 0.1 }}
      className={`group relative flex flex-col p-6 rounded-2xl border border-white/[0.06] bg-gradient-to-br from-[#0f0f1a] to-[#0a0a10] transition-all duration-300 ${card.hover} overflow-hidden`}
    >
      {/* Arrow on hover */}
      <div className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 transition-opacity duration-200">
        <FiArrowUpRight size={14} className="text-slate-500" />
      </div>

      {/* Icon with gradient ring */}
      <div className={`w-11 h-11 rounded-xl bg-gradient-to-br ${card.gradient} p-px mb-5 shrink-0`}>
        <div className="w-full h-full rounded-[11px] bg-[#0f0f1a] flex items-center justify-center">
          <Icon size={19} className="text-white" />
        </div>
      </div>

      <p className="font-mono text-[10px] uppercase tracking-widest text-slate-500 mb-1.5">
        {card.label}
      </p>
      <p className="text-slate-200 text-sm font-medium group-hover:text-white transition-colors truncate">
        {card.value}
      </p>
    </motion.a>
  );
}

export default function Contact() {
  const ref = useRef(null);
  const isInView = useInView(ref, { once: true, margin: '-100px' });

  return (
    <section id="contact" className="py-28 px-6">
      <div className="max-w-4xl mx-auto">
        <motion.div
          ref={ref}
          initial={{ opacity: 0, y: 20 }}
          animate={isInView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.6 }}
          className="text-center mb-16"
        >
          <span className="font-mono text-[#6c63ff] text-sm tracking-widest uppercase">// reach out</span>
          <h2 className="font-space text-4xl md:text-5xl font-bold text-white mt-3 mb-4">
            Get in Touch
          </h2>
          <p className="text-slate-400 max-w-md mx-auto">
            Open to full-time AI/ML roles. Let's build something intelligent together.
          </p>
        </motion.div>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-16">
          {CARDS.map((card, i) => (
            <ContactCard key={card.label} card={card} index={i} />
          ))}
        </div>

        {/* Footer */}
        <div className="text-center pt-8 border-t border-white/[0.04]">
          <p className="font-mono text-slate-600 text-sm">
            designed &amp; built by{' '}
            <span className="bg-gradient-to-r from-[#6c63ff] to-[#38bdf8] bg-clip-text text-transparent font-semibold">
              Hana Al Haris
            </span>{' '}
            · 2026
          </p>
        </div>
      </div>
    </section>
  );
}
